 98→export const mobileApi = {
 99→  async getJournals(cursor: string | null, limit = 10, userId?: string): Promise<CursorPage<JournalItem>> {
100→    const params = new URLSearchParams();
101→    params.set('limit', String(limit));
102→    if (cursor) {
