 41→    queryFn: () => mobileApi.getStreak(user?.id ?? ''),
 42→  });
 43→
 44→  const profile = userDataQuery.data?.userData?.[0] ?? null;
 45→  const streak = streakQuery.data?.currentStreak;
 46→
 47→  const parsedBg = useMemo(
 48→    () => parseProfileBackground(profile?.background),
 49→    [profile?.background],
 50→  );
 51→
 52→  const onSettingsPress = useCallback(() => {
 53→    Alert.alert('Sign Out', 'Are you sure you want to sign out?', [
 54→      {text: 'Cancel', style: 'cancel'},
 55→      {
 56→        text: 'Sign Out',
 57→        style: 'destructive',
 58→        onPress: async () => {
 59→          try {
 60→            await signOut();
 61→          } catch (error) {
 62→            Alert.alert(
 63→              'Sign out failed',
 64→              error instanceof Error ? error.message : 'Unknown error',
 65→            );
 66→          }
 67→        },
 68→      },
 69→    ]);
 70→  }, [signOut]);
 71→
 72→  const onEditProfile = useCallback(() => {
 73→    navigation.navigate('EditProfile');
 74→  }, [navigation]);
 75→
 76→  const onFollowersPress = useCallback(() => {
 77→    if (user?.id) {
 78→      navigation.navigate('FollowList', {userId: user.id, tab: 'followers'});
 79→    }
 80→  }, [navigation, user?.id]);
 81→
 82→  const onFollowingPress = useCallback(() => {
 83→    if (user?.id) {
 84→      navigation.navigate('FollowList', {userId: user.id, tab: 'following'});
 85→    }
 86→  }, [navigation, user?.id]);
 87→
 88→  const backdropElement = useMemo(() => {
 89→    if (parsedBg.type === 'gradient') {
 90→      const {start, end} = cssAngleToGradientPoints(parsedBg.angle);
 91→      return (
 92→        <LinearGradient
 93→          colors={parsedBg.colors}
 94→          locations={parsedBg.locations}
 95→          start={start}
 96→          end={end}
 97→          style={[StyleSheet.absoluteFill, styles.backdrop]}
 98→        />
 99→      );
100→    }
101→    if (parsedBg.type === 'image') {
102→      const dominantArr = profile?.dominant_colors
103→        ? profile.dominant_colors.split(',').map(c => c.trim())
104→        : null;
105→      const secondaryArr = profile?.secondary_colors
106→        ? profile.secondary_colors.split(',').map(c => c.trim())
107→        : null;
108→      const hasGradientOverlay =
109→        dominantArr && dominantArr.length > 0 && secondaryArr && secondaryArr.length > 0;
110→      return (
111→        <View style={[StyleSheet.absoluteFill, styles.backdrop]}>
112→          {hasGradientOverlay && (
113→            <LinearGradient
114→              colors={[...dominantArr, ...secondaryArr]}
115→              style={StyleSheet.absoluteFill}
116→            />
117→          )}
118→          <Image
119→            source={{uri: parsedBg.uri}}
120→            blurRadius={40}
121→            style={[StyleSheet.absoluteFill, {opacity: 0.3}]}
122→            resizeMode="cover"
123→          />
124→        </View>
125→      );
126→    }
127→    return null;
128→  }, [parsedBg, profile?.dominant_colors, profile?.secondary_colors]);
129→
130→  if (userDataQuery.isLoading) {
131→    return (
132→      <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]}>
