243→const styles = StyleSheet.create({
244→  list: {
245→    paddingHorizontal: spacing.lg,
246→    paddingBottom: 100,
247→  },
248→  skeletons: {
249→    gap: spacing.md,
250→    paddingTop: spacing.md,
251→  },
252→  footer: {
253→    paddingTop: spacing.md,
254→  },
255→  separator: {
256→    height: spacing.md,
257→  },
258→});
