 47→
 48→const getHotScore = (journal: JournalItem): number => {
 49→  if (typeof journal.hot_score === 'number') return journal.hot_score;
 50→  const likes = resolveCount(journal.like_count, journal.likes_count);
 51→  const comments = resolveCount(journal.comment_count, journal.comments_count);
 52→  const bookmarks = resolveCount(journal.bookmark_count);
 53→  return likes + comments * 2 + bookmarks * 3;
 54→};
 55→
 56→export function ExploreScreen({navigation}: Props) {
 57→  const {user, session} = useAuth();
 58→  const {colors} = useTheme();
 59→  const token = session?.access_token ?? '';
 60→  const {query, setQuery, activeTab, setActiveTab, isSearching, normalizedQuery, users, journals} = useSearch();
 61→  const [commentModal, setCommentModal] = useState<{
 62→    postId: string;
 63→    receiverId?: string;
 64→    commentCount: number;
 65→  } | null>(null);
 66→  const [repostModal, setRepostModal] = useState<{
 67→    journalId: string;
 68→    title?: string;
 69→    authorName?: string;
 70→    authorAvatar?: string;
 71→  } | null>(null);
 72→  // --- Data fetching ---
 73→
 74→  const hottestQuery = useQuery({
 75→    queryKey: ['explore-hottest-monthly', user?.id],
 76→    queryFn: () => mobileApi.getHottestMonthly(5, user?.id),
 77→    staleTime: 5 * 60 * 1000,
 78→  });
 79→
 80→  const hottestPosts = hottestQuery.data?.data ?? [];
 81→  const heroPost = hottestPosts[0] ?? null;
 82→  const runnerPosts = hottestPosts.slice(1);
 83→
 84→  // --- Interaction handlers ---
 85→
 86→  const reactionMutation = useMutation({
 87→    mutationFn: async ({
 88→      journalId,
 89→      receiverId,
 90→      reactionType,
 91→    }: {
 92→      journalId: string;
 93→      receiverId: string;
 94→      reactionType: string;
 95→    }) => {
 96→      if (!token) throw new Error('Please log in to react.');
 97→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 98→    },
 99→    onSettled: () => {
100→      queryClient.invalidateQueries({queryKey: ['explore-hottest-monthly']});
101→      queryClient.invalidateQueries({queryKey: ['search-journals']});
102→    },
103→  });
104→
105→  const bookmarkMutation = useBookmarkMutation(token, ['explore-hottest-monthly', user?.id]);
106→
107→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
108→    if (!token) return;
109→    reactionMutation.mutate({journalId, receiverId, reactionType});
110→  };
111→
112→  const handleBookmark = (journalId: string) => {
113→    bookmarkMutation.mutate(journalId);
114→  };
115→
116→  const handleComment = (journalId: string, receiverId?: string, commentCount?: number) => {
117→    setCommentModal({postId: journalId, receiverId, commentCount: commentCount ?? 0});
118→  };
119→
120→  const handleRepost = (journalId: string, title?: string, authorName?: string, authorAvatar?: string) => {
121→    setRepostModal({journalId, title, authorName, authorAvatar});
122→  };
123→
124→  const handleAuthorPress = (item: JournalItem) => {
125→    const authorId = item.users?.id ?? item.user_id;
126→    if (!authorId) return;
127→    if (authorId === user?.id) {
128→      navigation.navigate('Main' as any, {screen: 'Profile'});
129→    } else {
130→      navigation.navigate('VisitProfile', {
131→        userId: authorId,
132→        username: item.users?.username ?? undefined,
133→      });
134→    }
135→  };
136→
137→  // --- Render helpers ---
138→
139→  const renderPostCard = (item: JournalItem) => {
140→    const preview = extractPlainText(item.content).slice(0, 180);
141→    const likeCount = resolveCount(item.like_count, item.likes_count);
142→    const commentCount = resolveCount(item.comment_count, item.comments_count);
143→    const bookmarkCount = resolveCount(item.bookmark_count);
144→    const bannerImage = extractBannerImage(item.content, (item as any).images);
145→    const receiverId = item.user_id ?? item.users?.id ?? '';
146→    const readingTime = calculateReadingTime(extractPlainText(item.content));
147→    const isRepost = !!item.is_repost;
148→    const repostSource = isRepost ? item.repost_source : null;
149→    const repostSourcePreview = repostSource?.preview_text || '';
150→
151→    return (
152→      <PostCard
153→        title={item.title || 'Untitled Post'}
154→        bodyPreview={preview || 'No preview text available.'}
155→        authorName={item.users?.name || 'Unknown author'}
156→        authorAvatar={item.users?.image_url}
157→        authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
158→        bannerImage={bannerImage}
159→        postType={item.post_type ?? undefined}
160→        readingTime={readingTime}
161→        likeCount={likeCount}
162→        commentCount={commentCount}
163→        bookmarkCount={bookmarkCount}
164→        userReaction={item.user_reaction}
165→        isBookmarked={!!item.has_bookmarked}
166→        onReact={type => handleReact(item.id, receiverId, type)}
167→        onComment={() => handleComment(item.id, receiverId, commentCount)}
168→        onBookmark={() => handleBookmark(item.id)}
169→        onRepost={() =>
170→          handleRepost(
171→            item.id,
172→            item.title ?? undefined,
173→            item.users?.name ?? undefined,
174→            item.users?.image_url ?? undefined,
175→          )
176→        }
177→        onPress={() => navigation.navigate('PostDetail', {journalId: item.id})}
178→        onAuthorPress={() => handleAuthorPress(item)}
179→        isRepost={isRepost}
180→        repostCaption={item.repost_caption}
181→        repostSourceTitle={repostSource?.title}
182→        repostSourcePreview={repostSourcePreview}
183→        repostSourceAuthorName={repostSource?.users?.name}
184→        repostSourceAuthorAvatar={repostSource?.users?.image_url}
185→        onEmbeddedPress={
186→          repostSource
187→            ? () => navigation.navigate('PostDetail', {journalId: repostSource.id})
188→            : undefined
189→        }
190→      />
191→    );
192→  };
193→
194→  const renderRunnerRow = (item: JournalItem, rank: number) => {
195→    const hotScore = getHotScore(item);
196→    const bannerImage = extractBannerImage(item.content, (item as any).images);
197→
198→    return (
199→      <Pressable
200→        key={item.id}
201→        style={[styles.runnerRow, {borderBottomColor: colors.borderCard}]}
202→        onPress={() => navigation.navigate('PostDetail', {journalId: item.id})}>
203→        <Text
204→          style={[
205→            styles.runnerRank,
206→            {color: rank <= 3 ? '#d97706' : colors.textMuted},
207→          ]}>
208→          #{rank}
209→        </Text>
