  1→import React, {useMemo, useState} from 'react';
  2→import {
  3→  FlatList,
  4→  Pressable,
  5→  ScrollView,
  6→  StyleSheet,
  7→  Text,
  8→  View,
  9→} from 'react-native';
 10→import {useInfiniteQuery, useMutation} from '@tanstack/react-query';
 11→import {BottomTabScreenProps} from '@react-navigation/bottom-tabs';
 12→import {CompositeScreenProps} from '@react-navigation/native';
 13→import {NativeStackScreenProps} from '@react-navigation/native-stack';
 14→import {SafeAreaView} from 'react-native-safe-area-context';
 15→import {PostCard} from '../../components/PostCard/PostCard';
 16→import {PostCardSkeleton} from '../../components/SkeletonLoader';
 17→import {CommentModal} from '../../components/Comments';
 18→import {RepostModal} from '../../components/RepostModal';
 19→import {SearchInput} from '../../components/SearchInput';
 20→import {SearchResultsView} from '../../components/SearchResultsView';
 21→import {Chip} from '../../components/Chip';
 22→import {EmptyState} from '../../components/EmptyState';
 23→import {PenIcon} from '../../components/icons';
 24→import {useAuth} from '../../features/auth/AuthProvider';
 25→import {useTheme} from '../../theme/ThemeProvider';
 26→import {fonts, typeScale} from '../../theme/typography';
 27→import {spacing, radii, shadows} from '../../theme/spacing';
 28→import {
 29→  mobileApi,
 30→  type CursorPage,
 31→  type JournalItem,
 32→} from '../../lib/api/mobileApi';
 33→import {socialApi} from '../../lib/api/socialApi';
 34→import {queryClient} from '../../lib/queryClient';
 35→import {useBookmarkMutation} from '../../hooks/useSocialMutations';
 36→import {useSearch} from '../../hooks/useSearch';
 37→import {
 38→  extractPlainText,
 39→  extractBannerImage,
 40→  resolveCount,
 41→  getNextCursor,
 42→} from '../../lib/utils/journalHelpers';
 43→import type {MainTabParamList, RootStackParamList} from '../../navigation/types';
 44→
 45→type Props = CompositeScreenProps<
 46→  BottomTabScreenProps<MainTabParamList, 'Home'>,
 47→  NativeStackScreenProps<RootStackParamList>
 48→>;
 49→
 50→const PAGE_SIZE = 10;
 51→
 52→const QUICK_ACTIONS = [
 53→  {key: 'all', label: 'All'},
 54→  {key: 'journal', label: 'Journals'},
 55→] as const;
 56→
 57→export function HomeFeedScreen({navigation}: Props) {
 58→  const {user, session} = useAuth();
 59→  const {colors} = useTheme();
 60→  const token = session?.access_token ?? '';
 61→  const [refreshing, setRefreshing] = useState(false);
 62→  const [activeFilter, setActiveFilter] = useState('all');
 63→  const [commentModal, setCommentModal] = useState<{postId: string; receiverId?: string; commentCount: number} | null>(null);
 64→  const [repostModal, setRepostModal] = useState<{journalId: string; title?: string; authorName?: string; authorAvatar?: string} | null>(null);
 65→  const {query, setQuery, activeTab, setActiveTab, isSearching, normalizedQuery, users, journals} = useSearch();
 66→
 67→  const feedQuery = useInfiniteQuery({
 68→    queryKey: ['feed', user?.id],
 69→    queryFn: ({pageParam}) =>
 70→      mobileApi.getJournals(pageParam ?? null, PAGE_SIZE, user?.id),
 71→    initialPageParam: null as string | null,
 72→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 73→  });
 74→
 75→  const reactionMutation = useMutation({
 76→    mutationFn: async ({
 77→      journalId,
 78→      receiverId,
 79→      reactionType,
 80→    }: {
 81→      journalId: string;
 82→      receiverId: string;
 83→      reactionType: string;
 84→    }) => {
 85→      if (!token) throw new Error('Please log in to react.');
 86→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 87→    },
 88→    onMutate: async ({journalId, reactionType}) => {
 89→      await queryClient.cancelQueries({queryKey: ['feed']});
 90→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(
 91→        ['feed', user?.id],
 92→      );
 93→      if (prev) {
 94→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(
 95→          ['feed', user?.id],
 96→          old => {
 97→            if (!old) return old;
 98→            return {
 99→              ...old,
100→              pages: old.pages.map(page => ({
101→                ...page,
102→                data: page.data.map(item => {
103→                  if (item.id !== journalId) return item;
104→                  const removing = item.user_reaction === reactionType;
105→                  const currentCount =
106→                    (item.reaction_count?.[0]?.count ??
107→                      item.like_count?.[0]?.count ??
108→                      item.likes_count ??
109→                      0) as number;
110→                  const delta = removing ? -1 : item.user_reaction ? 0 : 1;
111→                  return {
112→                    ...item,
113→                    user_reaction: removing ? null : reactionType,
114→                    has_liked: removing ? false : true,
115→                    like_count: [{count: Math.max(0, currentCount + delta)}],
116→                  };
117→                }),
118→              })),
119→            };
120→          },
121→        );
122→      }
123→      return {prev};
124→    },
125→    onError: (_err, _vars, context) => {
126→      if (context?.prev) {
127→        queryClient.setQueryData(['feed', user?.id], context.prev);
128→      }
129→    },
130→    onSettled: () => {
131→      queryClient.invalidateQueries({queryKey: ['feed']});
132→    },
133→  });
134→
135→  const bookmarkMutation = useBookmarkMutation(token, ['feed', user?.id]);
136→
137→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
138→    if (!token) return;
139→    reactionMutation.mutate({journalId, receiverId, reactionType});
140→  };
141→
142→  const handleComment = (journalId: string, receiverId?: string, commentCount?: number) => {
143→    setCommentModal({postId: journalId, receiverId, commentCount: commentCount ?? 0});
144→  };
145→
146→  const handleBookmark = (journalId: string) => {
147→    bookmarkMutation.mutate(journalId);
148→  };
149→
150→  const handleRepost = (journalId: string, title?: string, authorName?: string, authorAvatar?: string) => {
151→    setRepostModal({journalId, title, authorName, authorAvatar});
152→  };
153→
154→  const handleAuthorPress = (item: JournalItem) => {
155→    const authorId = item.users?.id ?? item.user_id;
156→    if (!authorId) return;
157→    if (authorId === user?.id) {
158→      navigation.navigate('Main' as any, {screen: 'Profile'});
159→    } else {
160→      navigation.navigate('VisitProfile', {
161→        userId: authorId,
162→        username: item.users?.username ?? undefined,
163→      });
164→    }
165→  };
166→
167→  const posts = useMemo(
168→    () => feedQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
169→    [feedQuery.data?.pages],
170→  );
171→
172→  const onRefresh = async () => {
173→    setRefreshing(true);
174→    try {
175→      await feedQuery.refetch();
176→    } finally {
177→      setRefreshing(false);
178→    }
179→  };
180→
181→  const handleQuickAction = (key: string) => {
182→    setActiveFilter(key);
183→  };
184→
185→  return (
186→    <SafeAreaView
187→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
188→      edges={['top']}>
189→      {/* Branded header */}
190→      <View
191→        style={[
192→          styles.header,
193→          {borderBottomColor: colors.borderCard},
194→        ]}>
195→        <Text style={[styles.brandText, {color: colors.textHeading}]}>
196→          iskrib
197→        </Text>
198→        <SearchInput
199→          value={query}
200→          onChangeText={setQuery}
201→          placeholder="Search users or posts..."
202→          autoCapitalize="none"
203→          returnKeyType="search"
204→        />
205→      </View>
206→
207→      {isSearching ? (
208→        <SearchResultsView
209→          activeTab={activeTab}
210→          onTabChange={setActiveTab}
211→          users={users}
212→          journals={journals}
213→          normalizedQuery={normalizedQuery}
214→          onUserPress={(id, username) =>
215→            navigation.navigate('VisitProfile', {userId: id, username})
216→          }
217→          onPostPress={id =>
218→            navigation.navigate('PostDetail', {journalId: id})
219→          }
220→          onAuthorPress={handleAuthorPress}
221→          onReact={handleReact}
222→          onComment={handleComment}
223→          onBookmark={handleBookmark}
224→          onRepost={handleRepost}
225→          onEmbeddedPress={id =>
226→            navigation.navigate('PostDetail', {journalId: id})
227→          }
228→        />
229→      ) : (
230→        <>
231→          {/* Filter chips */}
232→          <View style={styles.chipRow}>
233→            <ScrollView
234→              horizontal
235→              showsHorizontalScrollIndicator={false}
236→              contentContainerStyle={styles.chipScroll}>
237→              {QUICK_ACTIONS.map(action => (
238→                <Chip
239→                  key={action.key}
240→                  label={action.label}
241→                  active={activeFilter === action.key}
242→                  onPress={() => handleQuickAction(action.key)}
243→                />
244→              ))}
245→            </ScrollView>
246→          </View>
247→
248→          {/* Feed */}
249→          <FlatList
250→            data={posts}
251→            onRefresh={onRefresh}
252→            refreshing={refreshing}
253→            onEndReachedThreshold={0.25}
254→            onEndReached={() => {
255→              if (feedQuery.hasNextPage && !feedQuery.isFetchingNextPage) {
256→                feedQuery.fetchNextPage();
257→              }
258→            }}
259→            contentContainerStyle={styles.listContent}
260→            showsVerticalScrollIndicator={false}
261→            ListEmptyComponent={
262→              feedQuery.isLoading ? (
263→                <View style={styles.skeletonList}>
264→                  <PostCardSkeleton />
265→                  <PostCardSkeleton />
266→                  <PostCardSkeleton />
267→                </View>
268→              ) : (
269→                <EmptyState
270→                  title="No posts yet"
271→                  subtitle="Pull to refresh or create your first journal post."
272→                />
273→              )
274→            }
275→            ListFooterComponent={
276→              feedQuery.isFetchingNextPage ? (
277→                <View style={styles.loadingMore}>
278→                  <PostCardSkeleton />
279→                </View>
280→              ) : null
281→            }
282→            keyExtractor={item => item.id}
283→            renderItem={({item}) => {
284→              const preview = extractPlainText(item.content).slice(0, 180);
285→              const likeCount = resolveCount(
286→                item.like_count,
287→                item.likes_count,
288→              );
289→              const commentCount = resolveCount(
290→                item.comment_count,
291→                item.comments_count,
292→              );
293→              const bookmarkCount = resolveCount(item.bookmark_count);
294→              const bannerImage = extractBannerImage(
295→                item.content,
296→                (item as any).images,
297→              );
298→
299→              const receiverId = item.user_id ?? item.users?.id ?? '';
300→
301→              const isRepost = !!item.is_repost;
302→              const repostSource = isRepost ? item.repost_source : null;
303→              const repostSourcePreview = repostSource?.preview_text || '';
304→
305→              return (
306→                <PostCard
307→                  title={item.title || 'Untitled Post'}
308→                  bodyPreview={preview || 'No preview text available.'}
309→                  authorName={item.users?.name || 'Unknown author'}
310→                  authorAvatar={item.users?.image_url}
311→                  authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
312→                  bannerImage={bannerImage}
313→                  postType={item.post_type}
314→                  likeCount={likeCount}
315→                  commentCount={commentCount}
316→                  bookmarkCount={bookmarkCount}
317→                  userReaction={item.user_reaction}
318→                  isBookmarked={!!item.has_bookmarked}
319→                  onReact={type => handleReact(item.id, receiverId, type)}
320→                  onComment={() => handleComment(item.id, receiverId, commentCount)}
321→                  onBookmark={() => handleBookmark(item.id)}
322→                  onRepost={() => handleRepost(item.id, item.title ?? undefined, item.users?.name ?? undefined, item.users?.image_url ?? undefined)}
323→                  onPress={() =>
324→                    navigation.navigate('PostDetail', {journalId: item.id})
325→                  }
326→                  onAuthorPress={() => handleAuthorPress(item)}
327→                  isRepost={isRepost}
328→                  repostCaption={item.repost_caption}
329→                  repostSourceTitle={repostSource?.title}
330→                  repostSourcePreview={repostSourcePreview}
331→                  repostSourceAuthorName={repostSource?.users?.name}
332→                  repostSourceAuthorAvatar={repostSource?.users?.image_url}
333→                  onEmbeddedPress={repostSource ? () => navigation.navigate('PostDetail', {journalId: repostSource.id}) : undefined}
334→                />
335→              );
336→            }}
337→            ItemSeparatorComponent={() => <View style={styles.separator} />}
338→          />
339→        </>
340→      )}
341→
342→      {commentModal && (
343→        <CommentModal
344→          visible
345→          postId={commentModal.postId}
346→          receiverId={commentModal.receiverId}
347→          commentCount={commentModal.commentCount}
348→          onClose={() => setCommentModal(null)}
349→        />
350→      )}
351→
352→      {repostModal && (
353→        <RepostModal
354→          visible
355→          sourceJournalId={repostModal.journalId}
356→          title={repostModal.title}
357→          authorName={repostModal.authorName}
358→          authorAvatar={repostModal.authorAvatar}
359→          onClose={() => setRepostModal(null)}
360→        />
361→      )}
362→
363→      {/* FAB Write Button */}
364→      <Pressable
365→        onPress={() => navigation.navigate('JournalEditor', {mode: 'create'})}
366→        style={({pressed}) => [
367→          styles.fab,
368→          {backgroundColor: colors.accentAmber},
369→          shadows(colors).elevated,
370→          pressed && styles.fabPressed,
371→        ]}>
372→        <PenIcon size={22} color="#1A1612" />
373→      </Pressable>
374→    </SafeAreaView>
375→  );
376→}
377→
378→const styles = StyleSheet.create({
379→  safe: {
380→    flex: 1,
381→  },
382→  header: {
383→    paddingHorizontal: spacing.lg,
384→    paddingVertical: spacing.md,
385→    borderBottomWidth: StyleSheet.hairlineWidth,
386→    gap: spacing.md,
387→  },
388→  brandText: {
389→    fontFamily: fonts.brand.semiBold,
390→    fontSize: 24,
391→    letterSpacing: 1,
392→  },
393→  chipRow: {
394→    paddingVertical: spacing.sm,
395→  },
396→  chipScroll: {
397→    paddingHorizontal: spacing.lg,
398→    gap: spacing.sm,
399→  },
400→  listContent: {
401→    paddingHorizontal: spacing.lg,
402→    paddingBottom: 100,
403→  },
404→  separator: {
405→    height: spacing.md,
406→  },
407→  skeletonList: {
408→    gap: spacing.md,
409→    paddingTop: spacing.md,
410→  },
411→  loadingMore: {
412→    paddingTop: spacing.md,
413→  },
414→  fab: {
415→    position: 'absolute',
416→    bottom: spacing.xxl,
417→    right: spacing.lg,
418→    width: 56,
419→    height: 56,
420→    borderRadius: 28,
421→    alignItems: 'center',
422→    justifyContent: 'center',
423→  },
424→  fabPressed: {
425→    transform: [{scale: 0.95}],
426→    opacity: 0.9,
427→  },
428→});
