 1→import React, {
 2→  createContext,
 3→  useCallback,
 4→  useContext,
 5→  useEffect,
 6→  useMemo,
 7→  useState,
 8→} from 'react';
 9→import {Appearance} from 'react-native';
10→import AsyncStorage from '@react-native-async-storage/async-storage';
11→import {lightPalette, darkPalette, type Palette} from './tokens';
12→
13→const STORAGE_KEY = '@iskrib_theme';
14→
15→type ThemeMode = 'light' | 'dark';
16→
17→interface ThemeContextValue {
18→  theme: ThemeMode;
19→  colors: Palette;
20→  isDark: boolean;
21→  toggleTheme: () => void;
22→  setTheme: (mode: ThemeMode) => void;
23→}
24→
25→const ThemeContext = createContext<ThemeContextValue | undefined>(undefined);
26→
27→export function ThemeProvider({children}: {children: React.ReactNode}) {
28→  const [theme, setThemeState] = useState<ThemeMode>(
29→    () => (Appearance.getColorScheme() as ThemeMode) ?? 'dark',
30→  );
31→  const [loaded, setLoaded] = useState(false);
32→
33→  useEffect(() => {
34→    AsyncStorage.getItem(STORAGE_KEY).then(stored => {
35→      if (stored === 'light' || stored === 'dark') {
36→        setThemeState(stored);
37→      }
38→      setLoaded(true);
39→    });
40→  }, []);
41→
42→  const setTheme = useCallback((mode: ThemeMode) => {
43→    setThemeState(mode);
44→    AsyncStorage.setItem(STORAGE_KEY, mode);
45→  }, []);
46→
47→  const toggleTheme = useCallback(() => {
48→    setTheme(theme === 'dark' ? 'light' : 'dark');
49→  }, [theme, setTheme]);
50→
51→  const value = useMemo<ThemeContextValue>(
52→    () => ({
53→      theme,
54→      colors: theme === 'dark' ? darkPalette : lightPalette,
55→      isDark: theme === 'dark',
56→      toggleTheme,
57→      setTheme,
58→    }),
59→    [theme, toggleTheme, setTheme],
60→  );
61→
62→  if (!loaded) {
63→    return null;
64→  }
65→
66→  return (
67→    <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>
68→  );
69→}
70→
71→export function useTheme(): ThemeContextValue {
72→  const ctx = useContext(ThemeContext);
73→  if (!ctx) {
74→    throw new Error('useTheme must be used within a ThemeProvider');
75→  }
76→  return ctx;
77→}
