  async getPromptResponses(promptId: string, cursor: string | null, limit = 10): Promise<{responses: JournalItem[]; before?: string}> {
    const params = new URLSearchParams();
    params.set('limit', String(limit));
    if (cursor) params.set('before', cursor);
    return apiRequest<{responses: JournalItem[]; before?: string}>(`/prompt/${encodeURIComponent(promptId)}/responses?${params.toString()}`, {
      method: 'GET',
    });
  },

  async getInterestSections(token: string): Promise<{sections?: Array<{name: string; journals: JournalItem[]}>}> {
    return apiRequest<{sections?: Array<{name: string; journals: JournalItem[]}>}>('/explore/interests', {
      method: 'GET',
      headers: {Authorization: `Bearer ${token}`},
    });
  },

  async getProfileMedia(token: string, cursor: string | null, limit = 20): Promise<{media: Array<{id: string; url: string; bucket?: string; path?: string}>; nextCursor?: string}> {
    const params = new URLSearchParams();
    params.set('limit', String(limit));
    if (cursor) params.set('cursor', cursor);
    return apiRequest('/profileMedia?' + params.toString(), {
      method: 'GET',
      headers: {Authorization: `Bearer ${token}`},
    });
  },

  async getVisitedProfileMedia(token: string, userId: string, cursor: string | null, limit = 20): Promise<{media: Array<{id: string; url: string}>; nextCursor?: string}> {
    const params = new URLSearchParams();
    params.set('userId', userId);
    params.set('limit', String(limit));
    if (cursor) params.set('cursor', cursor);
    return apiRequest('/visitedProfileMedia?' + params.toString(), {
      method: 'GET',
      headers: {Authorization: `Bearer ${token}`},
    });
  },

  async completeOnboarding(token: string, payload: {writingInterests: string[]; writingGoal: string}): Promise<{message?: string}> {
    return apiRequest<{message?: string}>('/complete-onboarding', {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${token}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(payload),
      retries: 0,
    });
  },

  async updateInterests(token: string, payload: {writingInterests: string[]; writingGoal: string}): Promise<{message?: string}> {
    return apiRequest<{message?: string}>('/update-interests', {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${token}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(payload),
      retries: 0,
    });
  },

  async updateFontColor(token: string, fontColor: string): Promise<{message?: string}> {
    const formData = new FormData();
    formData.append('fontColor', fontColor);
    return apiRequest<{message?: string}>('/updateFontColor', {
      method: 'POST',
      headers: {Authorization: `Bearer ${token}`},
      body: formData,
      retries: 0,
    });
  },

  async uploadBackground(token: string, formData: FormData): Promise<{data?: string}> {
    return apiRequest<{data?: string}>('/uploadBackground', {
      method: 'POST',
      headers: {Authorization: `Bearer ${token}`},
      body: formData,
      retries: 0,
      timeoutMs: 30000,
    });
  },

  async saveJournal(token: string, payload: { title: string; plainText: string; html?: string; privacy?: string }): Promise<{ message?: string }> {
    const formData = new FormData();

    const lexicalPayload = {
      root: {
        children: [
          {
            type: 'paragraph',
            children: [
              {
                type: 'text',
                text: payload.plainText,
                detail: 0,
                format: 0,
                mode: 'normal',
                style: '',
                version: 1,
              },
            ],
            direction: null,
            format: '',
            indent: 0,
            version: 1,
          },
        ],
        direction: null,
        format: '',
        indent: 0,
        type: 'root',
        version: 1,
      },
    };

    formData.append('title', payload.title);
    formData.append('content', JSON.stringify(lexicalPayload));
    formData.append('post_type', 'text');

    return apiRequest<{ message?: string }>('/save-journal', {
      method: 'POST',
      headers: {
        ...authHeaders(token),
      },
      body: formData,
      timeoutMs: 30000,
      retries: 0,
    });
  },
};

