import React, {useState} from 'react';
import {FlatList, Pressable, StyleSheet, Text, View} from 'react-native';
import {useQuery} from '@tanstack/react-query';
import {NativeStackScreenProps} from '@react-navigation/native-stack';
import {SafeAreaView} from 'react-native-safe-area-context';
import {Avatar} from '../../components/Avatar';
import {PrimaryButton} from '../../components/PrimaryButton';
import {EmptyState} from '../../components/EmptyState';
import {useAuth} from '../../features/auth/AuthProvider';
import {useTheme} from '../../theme/ThemeProvider';
import {useFollowMutation} from '../../hooks/useFollowMutation';
import {socialApi} from '../../lib/api/socialApi';
import {fonts} from '../../theme/typography';
import {spacing, radii} from '../../theme/spacing';
import type {RootStackParamList} from '../../navigation/types';

type Props = NativeStackScreenProps<RootStackParamList, 'FollowList'>;

type FollowUser = {
  id: string;
  name?: string;
  username?: string;
  image_url?: string;
  badge?: string;
};

function FollowRow({
  item,
  onPress,
  currentUserId,
  token,
}: {
  item: FollowUser;
  onPress: () => void;
  currentUserId?: string;
  token: string;
}) {
  const {colors} = useTheme();
  const followMutation = useFollowMutation(token, item.id);
  const isSelf = item.id === currentUserId;

  return (
    <Pressable style={[styles.row, {borderBottomColor: colors.borderCard}]} onPress={onPress}>
      <Avatar uri={item.image_url} name={item.name} size={44} badge={item.badge as any} />
      <View style={styles.rowInfo}>
        <Text style={[styles.rowName, {color: colors.textPrimary}]}>
          {item.name || 'User'}
        </Text>
        {item.username ? (
          <Text style={[styles.rowUsername, {color: colors.textMuted}]}>
            @{item.username}
          </Text>
        ) : null}
      </View>
      {!isSelf && (
        <PrimaryButton
          label={followMutation.isPending ? '...' : 'Follow'}
          onPress={() => followMutation.mutate()}
          kind="secondary"
        />
      )}
    </Pressable>
  );
}

export function FollowListScreen({route, navigation}: Props) {
  const {userId, tab: initialTab} = route.params;
  const {user, session} = useAuth();
  const {colors} = useTheme();
  const token = session?.access_token ?? '';
  const [activeTab, setActiveTab] = useState<'followers' | 'following'>(initialTab);

  const followsQuery = useQuery({
    queryKey: ['followsData', userId],
    enabled: Boolean(token && userId),
    queryFn: () => socialApi.getFollowsData(token, userId),
  });

  const followers: FollowUser[] = (followsQuery.data?.followers ?? []).map(f => ({
    id: f.users?.id ?? f.follower_id,
    name: f.users?.name,
    username: f.users?.username,
    image_url: f.users?.image_url,
    badge: f.users?.badge,
  }));

  const following: FollowUser[] = (followsQuery.data?.following ?? []).map(f => ({
    id: f.users?.id ?? f.following_id,
    name: f.users?.name,
    username: f.users?.username,
    image_url: f.users?.image_url,
    badge: f.users?.badge,
  }));

  const data = activeTab === 'followers' ? followers : following;

  const handleUserPress = (item: FollowUser) => {
    if (item.id === user?.id) {
      navigation.navigate('Main' as any, {screen: 'Profile'});
    } else {
      navigation.navigate('VisitProfile', {userId: item.id, username: item.username});
    }
  };

  return (
    <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]} edges={['top']}>
      <View style={[styles.tabBar, {borderBottomColor: colors.borderCard}]}>
        {(['followers', 'following'] as const).map(tab => {
          const active = activeTab === tab;
          return (
            <Pressable key={tab} style={styles.tab} onPress={() => setActiveTab(tab)}>
              <Text
                style={[
                  styles.tabText,
                  {
                    color: active ? colors.textHeading : colors.textMuted,
                    fontFamily: active ? fonts.ui.semiBold : fonts.ui.regular,
                  },
                ]}>
                {tab === 'followers' ? 'Followers' : 'Following'}
              </Text>
              {active ? (
                <View style={[styles.indicator, {backgroundColor: colors.accentAmber}]} />
              ) : null}
            </Pressable>
          );
        })}
      </View>

      <FlatList
        data={data}
        keyExtractor={item => item.id}
        contentContainerStyle={styles.list}
        ListEmptyComponent={
          followsQuery.isLoading ? null : (
            <EmptyState
              title={activeTab === 'followers' ? 'No followers yet' : 'Not following anyone'}
            />
          )
        }
        renderItem={({item}) => (
          <FollowRow
            item={item}
            onPress={() => handleUserPress(item)}
            currentUserId={user?.id}
            token={token}
          />
        )}
      />
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  safe: {
    flex: 1,
  },
  tabBar: {
    flexDirection: 'row',
    borderBottomWidth: StyleSheet.hairlineWidth,
  },
  tab: {
    flex: 1,
    alignItems: 'center',
    paddingVertical: spacing.md,
    position: 'relative',
  },
  tabText: {
    fontSize: 15,
  },
  indicator: {
    position: 'absolute',
    bottom: 0,
    left: '20%',
    right: '20%',
    height: 2.5,
    borderRadius: 2,
  },
  list: {
    paddingHorizontal: spacing.lg,
    paddingBottom: 100,
  },
  row: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: spacing.md,
    paddingVertical: spacing.md,
    borderBottomWidth: StyleSheet.hairlineWidth,
  },
  rowInfo: {
    flex: 1,
    gap: 2,
  },
  rowName: {
    fontFamily: fonts.ui.semiBold,
    fontSize: 15,
  },
  rowUsername: {
    fontFamily: fonts.ui.regular,
    fontSize: 13,
  },
});

