        selectedIconTint={colors.accentAmber}
        iconTint={colors.textMuted}
        style={[
          styles.toolbar,
          {borderColor: colors.borderLight, backgroundColor: colors.bgSecondary},
        ]}
      />

      <PrimaryButton
        label="Save Journal"
        onPress={() => saveMutation.mutate()}
        loading={saveMutation.isPending}
        disabled={!canSave}
      />
    </Screen>
  );
}

