interface DailyPromptCardProps {
  onWrite: (promptId: string, promptText: string) => void;
}

export function DailyPromptCard({onWrite}: DailyPromptCardProps) {
  const {colors} = useTheme();

  const promptQuery = useQuery({
    queryKey: ['prompt-today'],
    queryFn: () => mobileApi.getTodaysPrompt(),
    staleTime: 10 * 60 * 1000,
  });

  const prompt = promptQuery.data;
  if (!prompt?.id || !prompt?.prompt_text) return null;

  return (
    <View style={[styles.card, {backgroundColor: colors.bgCard, borderColor: colors.borderCard}]}>
      <Text style={[styles.label, {color: colors.accentAmber}]}>Daily Prompt</Text>
