          {longestStreak != null && longestStreak > 0 && (
            <Text style={[styles.longest, {color: colors.textMuted}]}>
              Longest: {longestStreak} days
            </Text>
          )}
        </View>
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    borderRadius: radii.xl,
