import React, {useState} from 'react';
import {Pressable, ScrollView, StyleSheet, Text, View} from 'react-native';
import {useQuery} from '@tanstack/react-query';
import {NativeStackScreenProps} from '@react-navigation/native-stack';
import {SafeAreaView} from 'react-native-safe-area-context';
import {useAuth} from '../../features/auth/AuthProvider';
import {useTheme} from '../../theme/ThemeProvider';
import {analyticsApi} from '../../lib/api/analyticsApi';
import {fonts, typeScale} from '../../theme/typography';
import {spacing, radii} from '../../theme/spacing';
import type {RootStackParamList} from '../../navigation/types';

type Props = NativeStackScreenProps<RootStackParamList, 'Analytics'>;

const RANGES = ['7d', '30d', '90d'] as const;

function StatCard({label, value, color}: {label: string; value: number; color: string}) {
  const {colors} = useTheme();
  return (
    <View style={[styles.statCard, {backgroundColor: colors.bgCard, borderColor: colors.borderCard}]}>
      <Text style={[styles.statValue, {color}]}>{value}</Text>
      <Text style={[styles.statLabel, {color: colors.textMuted}]}>{label}</Text>
    </View>
  );
}

export function AnalyticsDashboardScreen({navigation}: Props) {
  const {session} = useAuth();
  const {colors} = useTheme();
  const token = session?.access_token ?? '';
  const [range, setRange] = useState<string>('30d');

  const analyticsQuery = useQuery({
    queryKey: ['analytics', range],
    enabled: Boolean(token),
    queryFn: () => analyticsApi.getWriterAnalytics(token, range),
  });

  const data = analyticsQuery.data?.analytics;

  return (
    <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]} edges={['top']}>
      <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>
        <Text style={[typeScale.h1, {color: colors.textHeading}]}>Analytics</Text>

        {/* Range selector */}
        <View style={styles.rangeRow}>
          {RANGES.map(r => (
            <Pressable
              key={r}
              style={[
                styles.rangeBtn,
                {
                  backgroundColor: range === r ? colors.accentAmber : colors.bgCard,
                  borderColor: range === r ? colors.accentAmber : colors.borderCard,
                },
              ]}
              onPress={() => setRange(r)}>
              <Text style={[styles.rangeBtnText, {color: range === r ? '#1A1612' : colors.textSecondary}]}>
                {r}
              </Text>
            </Pressable>
          ))}
        </View>

        {/* Stats grid */}
        <View style={styles.statsGrid}>
          <StatCard label="Views" value={data?.views ?? 0} color={colors.accentAmber} />
          <StatCard label="Likes" value={data?.likes ?? 0} color="#EF4444" />
          <StatCard label="Comments" value={data?.comments ?? 0} color="#3B82F6" />
          <StatCard label="Bookmarks" value={data?.bookmarks ?? 0} color="#10B981" />
        </View>

        {/* Publishes */}
        <View style={[styles.publishCard, {backgroundColor: colors.bgCard, borderColor: colors.borderCard}]}>
          <Text style={[styles.publishLabel, {color: colors.textMuted}]}>Posts Published</Text>
          <Text style={[styles.publishValue, {color: colors.textHeading}]}>{data?.publishes ?? 0}</Text>
        </View>

        {/* Top posts */}
        {data?.topPosts && data.topPosts.length > 0 && (
          <View>
            <Text style={[typeScale.h3, {color: colors.textHeading, marginBottom: spacing.sm}]}>Top Posts</Text>
            {data.topPosts.map((post, i) => (
              <Pressable
                key={post.id}
                style={[styles.topPostRow, {borderBottomColor: colors.borderCard}]}
                onPress={() => navigation.navigate('PostDetail', {journalId: post.id})}>
                <Text style={[styles.topPostRank, {color: colors.textMuted}]}>#{i + 1}</Text>
                <Text style={[styles.topPostTitle, {color: colors.textPrimary}]} numberOfLines={1}>
                  {post.title || 'Untitled'}
                </Text>
                <Text style={[styles.topPostViews, {color: colors.textMuted}]}>
                  {post.views ?? 0} views
                </Text>
              </Pressable>
            ))}
          </View>
        )}
      </ScrollView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  safe: {flex: 1},
  content: {padding: spacing.lg, gap: spacing.xl, paddingBottom: 100},
  rangeRow: {flexDirection: 'row', gap: spacing.sm},
  rangeBtn: {
    paddingHorizontal: spacing.lg,
    paddingVertical: spacing.sm,
    borderRadius: radii.pill,
    borderWidth: 1,
  },
  rangeBtnText: {fontFamily: fonts.ui.semiBold, fontSize: 13},
  statsGrid: {flexDirection: 'row', flexWrap: 'wrap', gap: spacing.md},
  statCard: {
    flex: 1,
    minWidth: '45%',
    borderRadius: radii.xl,
    borderWidth: 1,
    padding: spacing.lg,
    alignItems: 'center',
    gap: 4,
  },
  statValue: {fontFamily: fonts.heading.bold, fontSize: 28},
  statLabel: {fontFamily: fonts.ui.regular, fontSize: 12},
  publishCard: {
    borderRadius: radii.xl,
    borderWidth: 1,
    padding: spacing.lg,
    alignItems: 'center',
    gap: 4,
  },
  publishLabel: {fontFamily: fonts.ui.regular, fontSize: 12},
  publishValue: {fontFamily: fonts.heading.bold, fontSize: 32},
  topPostRow: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: spacing.sm,
    paddingVertical: spacing.md,
    borderBottomWidth: StyleSheet.hairlineWidth,
  },
  topPostRank: {fontFamily: fonts.ui.bold, fontSize: 14, width: 28},
  topPostTitle: {fontFamily: fonts.ui.semiBold, fontSize: 14, flex: 1},
  topPostViews: {fontFamily: fonts.ui.regular, fontSize: 12},
});

