import React from 'react';
import {Modal, Pressable, StyleSheet, Text, View} from 'react-native';
import {useTheme} from '../theme/ThemeProvider';
import {fonts, typeScale} from '../theme/typography';
import {spacing, radii, shadows} from '../theme/spacing';
import {FireIcon} from './icons';
import type {WeeklyRecapData} from '../lib/api/analyticsApi';

interface WeeklyRecapModalProps {
  visible: boolean;
  recap: WeeklyRecapData;
  onDismiss: () => void;
}

export function WeeklyRecapModal({visible, recap, onDismiss}: WeeklyRecapModalProps) {
  const {colors} = useTheme();

  return (
    <Modal visible={visible} transparent animationType="fade">
      <View style={styles.overlay}>
        <View style={[styles.card, {backgroundColor: colors.bgElevated}, shadows(colors).modal]}>
          <Text style={[styles.title, {color: colors.accentAmber}]}>Weekly Recap</Text>

          <View style={styles.statsRow}>
            <View style={styles.statItem}>
              <Text style={[styles.statNumber, {color: colors.textHeading}]}>
                {recap.postsWritten ?? 0}
              </Text>
              <Text style={[styles.statLabel, {color: colors.textMuted}]}>Posts Written</Text>
            </View>
            <View style={styles.statItem}>
              <Text style={[styles.statNumber, {color: colors.textHeading}]}>
                {recap.totalViews ?? 0}
              </Text>
              <Text style={[styles.statLabel, {color: colors.textMuted}]}>Views</Text>
            </View>
            <View style={styles.statItem}>
              <Text style={[styles.statNumber, {color: colors.textHeading}]}>
                {recap.newFollowers ?? 0}
              </Text>
              <Text style={[styles.statLabel, {color: colors.textMuted}]}>New Followers</Text>
            </View>
          </View>

          {recap.topPost?.title && (
            <View style={[styles.topPost, {backgroundColor: colors.bgSecondary}]}>
              <FireIcon size={16} color="#F59E0B" />
              <View style={styles.topPostInfo}>
                <Text style={[styles.topPostLabel, {color: colors.textMuted}]}>Top Post</Text>
                <Text style={[styles.topPostTitle, {color: colors.textPrimary}]} numberOfLines={1}>
                  {recap.topPost.title}
                </Text>
              </View>
            </View>
          )}

          <Pressable style={[styles.dismissBtn, {backgroundColor: colors.accentAmber}]} onPress={onDismiss}>
            <Text style={styles.dismissText}>Got it!</Text>
          </Pressable>
        </View>
      </View>
    </Modal>
  );
}

const styles = StyleSheet.create({
  overlay: {
    flex: 1,
    backgroundColor: 'rgba(0,0,0,0.6)',
    justifyContent: 'center',
