    },
    onSuccess: () => {
      queryClient.invalidateQueries({queryKey: ['profile']});
      Alert.alert('Saved', 'Background updated.');
    },
    onError: e => {
      if (e instanceof Error && e.message === 'Cancelled') return;
      Alert.alert('Error', e instanceof Error ? e.message : 'Failed');
    },
  });

  return (
    <SafeAreaView style={[styles.safe, {backgroundColor: colors.bgPrimary}]} edges={['top']}>
      <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>
        <Text style={[typeScale.h1, {color: colors.textHeading}]}>Customize Profile</Text>

        {/* Font Color */}
        <View style={styles.section}>
          <Text style={[styles.sectionTitle, {color: colors.textHeading}]}>Font Color</Text>
          <Text style={[styles.sectionSubtitle, {color: colors.textMuted}]}>
            Choose a color for your profile text
          </Text>
          <View style={styles.colorGrid}>
            {COLOR_PALETTE.map(color => (
              <Pressable
                key={color}
                style={[
                  styles.colorSwatch,
                  {backgroundColor: color},
                  selectedColor === color && styles.colorSwatchSelected,
                ]}
                onPress={() => setSelectedColor(color)}
              />
            ))}
          </View>
          {selectedColor && (
            <View style={styles.previewRow}>
              <Text style={[styles.previewLabel, {color: colors.textMuted}]}>Preview:</Text>
              <Text style={[styles.previewText, {color: selectedColor}]}>Your Name</Text>
            </View>
          )}
          <PrimaryButton
            label="Save Font Color"
            onPress={() => fontColorMutation.mutate()}
            loading={fontColorMutation.isPending}
            disabled={!selectedColor}
          />
        </View>

        {/* Background */}
        <View style={styles.section}>
          <Text style={[styles.sectionTitle, {color: colors.textHeading}]}>Background Image</Text>
          <Text style={[styles.sectionSubtitle, {color: colors.textMuted}]}>
            Upload a background image for your profile
          </Text>
          <PrimaryButton
            label="Choose Image"
            onPress={() => backgroundMutation.mutate()}
            loading={backgroundMutation.isPending}
            kind="secondary"
          />
        </View>
      </ScrollView>
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  safe: {flex: 1},
  content: {padding: spacing.lg, gap: spacing.xxl, paddingBottom: 100},
  section: {gap: spacing.md},
  sectionTitle: {fontFamily: fonts.heading.semiBold, fontSize: 18},
  sectionSubtitle: {fontFamily: fonts.ui.regular, fontSize: 13},
  colorGrid: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    gap: spacing.sm,
  },
  colorSwatch: {
    width: 40,
    height: 40,
    borderRadius: 20,
    borderWidth: 2,
    borderColor: 'transparent',
  },
  colorSwatchSelected: {
    borderColor: '#F59E0B',
    borderWidth: 3,
  },
  previewRow: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: spacing.sm,
  },
  previewLabel: {fontFamily: fonts.ui.regular, fontSize: 13},
  previewText: {fontFamily: fonts.heading.bold, fontSize: 20},
});

