  1→import React, {useMemo, useState} from 'react';
  2→import {FlatList, StyleSheet, View} from 'react-native';
  3→import {useInfiniteQuery, useMutation} from '@tanstack/react-query';
  4→import {useNavigation} from '@react-navigation/native';
  5→import type {NativeStackNavigationProp} from '@react-navigation/native-stack';
  6→import {PostCard} from '../../components/PostCard/PostCard';
  7→import {PostCardSkeleton} from '../../components/SkeletonLoader';
  8→import {CommentModal} from '../../components/Comments';
  9→import {RepostModal} from '../../components/RepostModal';
 10→import {EmptyState} from '../../components/EmptyState';
 11→import {
 12→  extractPlainText,
 13→  extractBannerImage,
 14→  resolveCount,
 15→  getNextCursor,
 16→} from '../../lib/utils/journalHelpers';
 17→import {mobileApi, type CursorPage, type JournalItem} from '../../lib/api/mobileApi';
 18→import {socialApi} from '../../lib/api/socialApi';
 19→import {queryClient} from '../../lib/queryClient';
 20→import {useAuth} from '../../features/auth/AuthProvider';
 21→import {useBookmarkMutation} from '../../hooks/useSocialMutations';
 22→import {spacing} from '../../theme/spacing';
 23→import type {RootStackParamList} from '../../navigation/types';
 24→
 25→const PAGE_SIZE = 10;
 26→
 27→interface ProfileWritingsTabProps {
 28→  userId: string;
 29→  headerComponent?: React.ReactElement;
 30→}
 31→
 32→export function ProfileWritingsTab({userId, headerComponent}: ProfileWritingsTabProps) {
 33→  const navigation = useNavigation<NativeStackNavigationProp<RootStackParamList>>();
 34→  const {user, session} = useAuth();
 35→  const token = session?.access_token ?? '';
 36→  const [commentModal, setCommentModal] = useState<{postId: string; receiverId?: string; commentCount: number} | null>(null);
 37→  const [repostModal, setRepostModal] = useState<{journalId: string; title?: string; authorName?: string; authorAvatar?: string} | null>(null);
 38→
 39→  const query = useInfiniteQuery({
 40→    queryKey: ['profileWritings', userId],
 41→    queryFn: ({pageParam}) =>
 42→      mobileApi.getUserJournals(token, userId, pageParam ?? null, PAGE_SIZE),
 43→    initialPageParam: null as string | null,
 44→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 45→  });
 46→
 47→  const queryKey = ['profileWritings', userId];
 48→
 49→  const reactionMutation = useMutation<
 50→    {message?: string},
 51→    Error,
 52→    {journalId: string; receiverId: string; reactionType: string},
 53→    {prev?: {pages: CursorPage<JournalItem>[]}}
 54→  >({
 55→    mutationFn: async ({journalId, receiverId, reactionType}) => {
 56→      if (!token) throw new Error('Please log in to react.');
 57→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 58→    },
 59→    onMutate: async ({journalId, reactionType}) => {
 60→      await queryClient.cancelQueries({queryKey});
 61→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(queryKey);
 62→      if (prev) {
 63→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(queryKey, old => {
 64→          if (!old) return old;
 65→          return {
 66→            ...old,
 67→            pages: old.pages.map(page => ({
 68→              ...page,
 69→              data: page.data.map(item => {
 70→                if (item.id !== journalId) return item;
 71→                const removing = item.user_reaction === reactionType;
 72→                const currentCount =
 73→                  (item.reaction_count?.[0]?.count ??
 74→                    item.like_count?.[0]?.count ??
 75→                    item.likes_count ??
 76→                    0) as number;
 77→                const delta = removing ? -1 : item.user_reaction ? 0 : 1;
 78→                return {
 79→                  ...item,
 80→                  user_reaction: removing ? null : reactionType,
 81→                  has_liked: removing ? false : true,
 82→                  like_count: [{count: Math.max(0, currentCount + delta)}],
 83→                };
 84→              }),
 85→            })),
 86→          };
 87→        });
 88→      }
 89→      return {prev};
 90→    },
 91→    onError: (_err, _vars, context) => {
 92→      if (context?.prev) {
 93→        queryClient.setQueryData(queryKey, context.prev);
 94→      }
 95→    },
 96→    onSettled: () => {
 97→      queryClient.invalidateQueries({queryKey});
 98→    },
 99→  });
100→
101→  const bookmarkMutation = useBookmarkMutation(token, queryKey);
102→
103→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
104→    if (!token) return;
105→    reactionMutation.mutate({journalId, receiverId, reactionType});
106→  };
107→
108→  const handleComment = (journalId: string, receiverId?: string, commentCount?: number) => {
109→    setCommentModal({postId: journalId, receiverId, commentCount: commentCount ?? 0});
110→  };
111→
112→  const handleBookmark = (journalId: string) => {
113→    bookmarkMutation.mutate(journalId);
114→  };
115→
116→  const handleRepost = (journalId: string, title?: string, authorName?: string, authorAvatar?: string) => {
117→    setRepostModal({journalId, title, authorName, authorAvatar});
118→  };
119→
120→  const posts = useMemo(
121→    () => query.data?.pages.flatMap(page => page.data ?? []) ?? [],
122→    [query.data?.pages],
123→  );
124→
125→  return (
126→    <>
127→    <FlatList
128→      data={posts}
129→      keyExtractor={item => item.id}
130→      showsVerticalScrollIndicator={false}
131→      contentContainerStyle={styles.list}
132→      ListHeaderComponent={headerComponent}
133→      onEndReachedThreshold={0.3}
134→      onEndReached={() => {
135→        if (query.hasNextPage && !query.isFetchingNextPage) {
136→          query.fetchNextPage();
137→        }
138→      }}
139→      ListEmptyComponent={
140→        query.isLoading ? (
141→          <View style={styles.skeletons}>
142→            <PostCardSkeleton />
143→            <PostCardSkeleton />
144→            <PostCardSkeleton />
145→          </View>
146→        ) : (
147→          <EmptyState
148→            title="No writings yet"
149→            subtitle="Journal posts will appear here."
150→          />
151→        )
152→      }
153→      ListFooterComponent={
154→        query.isFetchingNextPage ? (
155→          <View style={styles.footer}>
156→            <PostCardSkeleton />
157→          </View>
158→        ) : null
159→      }
160→      renderItem={({item}) => {
161→        const preview = extractPlainText(item.content).slice(0, 180);
162→        const likeCount = resolveCount(item.like_count, item.likes_count);
163→        const commentCount = resolveCount(item.comment_count, item.comments_count);
164→        const bookmarkCount = resolveCount(item.bookmark_count);
165→        const bannerImage = extractBannerImage(item.content, (item as any).images);
166→
167→        const handleAuthorPress = () => {
168→          const authorId = item.users?.id ?? item.user_id;
169→          if (!authorId) return;
170→          if (authorId === user?.id) {
171→            navigation.navigate('Main' as any, {screen: 'Profile'});
172→          } else {
173→            navigation.navigate('VisitProfile', {
174→              userId: authorId,
175→              username: item.users?.username ?? undefined,
176→            });
177→          }
178→        };
179→
180→        const receiverId = item.user_id ?? item.users?.id ?? '';
181→
182→        const isRepost = !!item.is_repost;
183→        const repostSource = isRepost ? item.repost_source : null;
184→        const repostSourcePreview = repostSource?.preview_text || '';
185→
186→        return (
187→          <PostCard
188→            title={item.title || 'Untitled Post'}
189→            bodyPreview={preview || 'No preview text available.'}
190→            authorName={item.users?.name || 'Unknown author'}
191→            authorAvatar={item.users?.image_url}
192→            authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
193→            bannerImage={bannerImage}
194→            postType={item.post_type ?? undefined}
195→            likeCount={likeCount}
196→            commentCount={commentCount}
197→            bookmarkCount={bookmarkCount}
198→            isBookmarked={!!item.has_bookmarked}
199→            userReaction={item.user_reaction}
200→            onReact={type => handleReact(item.id, receiverId, type)}
201→            onComment={() => handleComment(item.id, receiverId, commentCount)}
202→            onBookmark={() => handleBookmark(item.id)}
203→            onRepost={() => handleRepost(item.id, item.title ?? undefined, item.users?.name ?? undefined, item.users?.image_url ?? undefined)}
204→            onPress={() =>
205→              navigation.navigate('PostDetail', {journalId: item.id})
206→            }
207→            onAuthorPress={handleAuthorPress}
208→            isRepost={isRepost}
209→            repostCaption={item.repost_caption}
210→            repostSourceTitle={repostSource?.title}
211→            repostSourcePreview={repostSourcePreview}
212→            repostSourceAuthorName={repostSource?.users?.name}
213→            repostSourceAuthorAvatar={repostSource?.users?.image_url}
214→            onEmbeddedPress={repostSource ? () => navigation.navigate('PostDetail', {journalId: repostSource.id}) : undefined}
215→          />
216→        );
217→      }}
218→      ItemSeparatorComponent={() => <View style={styles.separator} />}
219→    />
220→    {commentModal && (
221→      <CommentModal
222→        visible
223→        postId={commentModal.postId}
224→        receiverId={commentModal.receiverId}
225→        commentCount={commentModal.commentCount}
226→        onClose={() => setCommentModal(null)}
227→      />
228→    )}
229→    {repostModal && (
230→      <RepostModal
231→        visible
232→        sourceJournalId={repostModal.journalId}
233→        title={repostModal.title}
234→        authorName={repostModal.authorName}
235→        authorAvatar={repostModal.authorAvatar}
236→        onClose={() => setRepostModal(null)}
237→      />
238→    )}
239→    </>
240→  );
241→}
