211→            .in('journal_id', journalIds)
212→            .eq('user_id', userId),
213→        supabase
214→            .from('reactions')
215→            .select('journal_id, reaction_type')
216→            .in('journal_id', journalIds)
217→            .eq('user_id', userId)
218→    ]);
